// Parse input whether from Schedule or Webhook.
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const client_id = body.client_id || null;
const agent_id = body.agent_id || null;
const plan_date = body.plan_date || new Date().toISOString().slice(0, 10);

// When fired from the schedule, we have no client_id — caller must iterate.
// For now the schedule path returns an empty array and the webhook path
// returns a single item.
if (!client_id) {
  return { json: { _multi: true, plan_date } };
}
return { json: { client_id, agent_id, plan_date, _multi: false } };

// Fan out into per-client items.
const arr = Array.isArray($input.item.json) ? $input.item.json : [];
const plan_date = $('Parse Input').first().json.plan_date;
return arr.map(function(c) { return { json: { client_id: c.id, agent_id: null, plan_date } }; });

// Bundle base tasks + build Claude prompt.
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const parsed = $('Parse Input').first().json;
// If Fan Out ran, parsed won't match this item — use the item itself.
const ctx = $input.all().length === 1 && !parsed._multi ? parsed : { client_id: rows[0] ? rows[0]._client_id : null, plan_date: parsed.plan_date };

const system_prompt = [
  'You are Crystallux Morning Priority Copilot.',
  'Re-rank the supplied task list so the agent starts with the single highest-leverage item.',
  'Rules:',
  ' - Output STRICT JSON only.',
  ' - Preserve every task id; do NOT add or remove tasks.',
  ' - Output shape: { "tasks": [...], "summary_line": "<one-sentence morning briefing, <140 chars>" }',
  ' - Each task keeps its fields + adds a numeric "rank" (1-based) + a <120 char "reason" explaining why it is at that rank.',
  ' - Prefer: SLA-breached replies first, then hot leads (>=80), then no-show rebooks, then upcoming calls (sorted by time), then stale follow-ups.',
  ' - If a tie, prefer leads with higher lead_score.',
  ' - Never claim urgency that is not supported by the task fields.'
].join('\n');

const user_prompt = [
  'CLIENT ID: ' + ctx.client_id,
  'PLAN DATE: ' + ctx.plan_date,
  '',
  'BASE TASKS (already ranked heuristically):',
  JSON.stringify(rows, null, 2),
  '',
  'Return the JSON now.'
].join('\n');

return { json: {
  client_id: rows[0] ? rows[0]._client_id || parsed.client_id : parsed.client_id,
  agent_id: parsed.agent_id || null,
  plan_date: parsed.plan_date,
  base_tasks: rows,
  system_prompt,
  user_prompt
} };

// Parse Claude; fall back to base-rank if Claude fails.
const resp = $input.item.json || {};
const prep = $('Prep Claude Prompt').first().json;

let parsed = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  if (text.trim().length > 0) parsed = JSON.parse(text.trim());
} catch (e) { parsed = null; }

if (!parsed || !Array.isArray(parsed.tasks)) {
  const base = prep.base_tasks || [];
  const fallback_tasks = base.map(function(t, i) { return Object.assign({}, t, { rank: i + 1, reason: t.reason || 'heuristic rank' }); });
  const sla = fallback_tasks.filter(function(t) { return t.sla_breached; }).length;
  return { json: Object.assign({}, prep, { tasks: fallback_tasks, summary_line: fallback_tasks.length + ' tasks · ' + sla + ' SLA-breached · heuristic order (Claude unavailable)', generator_source: 'rpc' }) };
}

return { json: Object.assign({}, prep, { tasks: parsed.tasks, summary_line: parsed.summary_line || ((parsed.tasks || []).length + ' tasks'), generator_source: 'claude' }) };

// Build response
const upsertResp = $input.item.json;
const prep = $('Parse + Fallback').first().json;
let plan_id = null;
if (typeof upsertResp === 'string') plan_id = upsertResp;
else if (upsertResp && upsertResp.id) plan_id = upsertResp.id;
else if (Array.isArray(upsertResp) && upsertResp.length > 0 && upsertResp[0].upsert_daily_plan) plan_id = upsertResp[0].upsert_daily_plan;
return { json: { ok: true, plan_id, task_count: (prep.tasks || []).length, summary: prep.summary_line || '' } };
